import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton } from "@coreui/react";
import FormInput from 'src/utils/FormInput';
import { createPersona, getPersonaData, updatePersona } from 'src/components/services/PersonaApi';
import GoBackComponent from 'src/utils/GoBackComponent';

const PersonaForm = (props) => {

    const { id, type } = props;
    const [formData, setFormData] = useState({ persona: "" });
    const [errors, setErrors] = useState({});
    const [errorMessage, setErrorMessage] = useState("");
    const navigate = useNavigate();

    useEffect(() => {
        if (type === "UPDATE") {
            getPersonaDataById(id);
        }
    }, [])

    const handleChange = (event) => {
        setFormData({ ...formData, [event.target.name]: event.target.value.trimStart().replace(/  +/g, ' ') });
    };

    const validateForm = () => {
        let errors = [];
        let formIsValid = true;
        if (formData.persona === "") {
            errors['persona'] = "Please enter persona";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async () => {
        if (validateForm()) {
            let postData = {
                persona: formData?.persona?.trim()
            }
            let persona = {};
            if (props.type === "CREATE") {
                persona = await createPersona(postData);
            } else {
                persona = await updatePersona(postData, id);
            }
            if (persona?.code === 201 || persona?.code === 202) {
                navigate('/persona');
            }
            if (persona?.code === 409) {
                setErrorMessage(persona?.message)
            }
            setTimeout(() => {
                setErrorMessage();
            }, 2000);
        }
    };

    const getPersonaDataById = async (id) => {
        let response = await getPersonaData(id);
        if (response?.code === 200) {
            let data = {
                persona: response?.results?.persona
            }
            setFormData(data);
        }
    }

    return (
        <>
            <GoBackComponent goBackData={"persona"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={8}>
                        <FormInput
                            value={formData.persona}
                            label={"Persona"}
                            name={"persona"}
                            onChange={handleChange}
                            required={true}
                            error={errors['persona']}
                        />
                        {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                    </CCol>

                    <CCol md={12}>
                        <CButton color="primary" onClick={handleSubmit} className="d-block">
                            {props.type === "CREATE" ? "Create" : "Update"}
                        </CButton>
                    </CCol>
                </CForm>
            </div>
        </>
    );
}

export default PersonaForm;
